# Base utility module providing mathematical operations

PI: float = 3.14159

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"

def double_value(x: int) -> int:
    """Double an integer value"""
    return x * 2

def clamp_value(value: int, min_val: int, max_val: int) -> int:
    """Clamp value between min and max"""
    if value < min_val:
        return min_val
    if value > max_val:
        return max_val
    return value

