# Extended utilities that build on base_utils
from base_utils import Shape, double_value

class Rectangle(Shape):
    width: int
    height: int

    def __init__(self, name: str, width: int, height: int):
        super().__init__(name)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height to float

    @override
    def describe(self) -> str:
        base: str = super().describe()
        return f"{base} (Rectangle {self.width}x{self.height})"

def scale_dimensions(width: int, height: int, factor: int) -> tuple[int, int]:
    """Scale dimensions by a factor using double_value for demo"""
    scaled_w: int = double_value(width) if factor == 2 else width * factor
    scaled_h: int = double_value(height) if factor == 2 else height * factor
    return (scaled_w, scaled_h)
